const post = $input.first().json;
const motivos = [];
const ajustes = [];

const legendaFB = (post.legenda_facebook || '').toLowerCase();
const legendaIG = (post.legenda_instagram || '').toLowerCase();
const cta = (post.cta || '').toLowerCase();
const allText = legendaFB + ' ' + legendaIG + ' ' + cta;

// --- VERIFICAÇÕES DE TEXTO ---

// 1. Acusação direta com pronome + atributo sensível
const padroesSensiveis = [
  /\b(seu|sua|seus|suas|voc[eê])\b.{0,30}(insegur|risco|falha|problem|perigo|preju[ií]z|d[ií]vida|inadimpl|ameaç)/i,
  /\b(seu|sua)\s+(condom[ií]nio|pr[eé]dio|empresa).{0,20}(est[aá]\s+insegur|est[aá]\s+em\s+risco|pode\s+sofrer)/i
];
for (const p of padroesSensiveis) {
  if (p.test(allText)) {
    motivos.push('Texto usa pronome pessoal ligado a atributo sensível (risco/falha/insegurança)');
    break;
  }
}

// 2. Promessas proibidas
const promessas = [
  /garant(e|imos|ia|ido)/i,
  /nunca\s+mais/i,
  /blindado\s+24/i,
  /seguran[cç]a\s+total/i,
  /economia\s+garantida/i,
  /risco\s+de\s+morte/i,
  /trag[eé]dia/i,
  /perigo\s+total/i,
  /zero\s+risco/i,
  /100%\s+segur/i,
  /elimina(r|mos)?\s+(todo|qualquer)\s+(risco|problema)/i
];
for (const p of promessas) {
  if (p.test(allText)) {
    motivos.push(`Texto contém promessa proibida: ${p.source}`);
  }
}

// 3. Sensacionalismo
const sensacionalismo = [
  /urg[eê]nt[eí]ssimo/i,
  /alerta\s+(m[aá]ximo|vermelho|total)/i,
  /bomba!|exclusivo!/i,
  /chocante/i,
  /inacredit[aá]vel/i
];
for (const p of sensacionalismo) {
  if (p.test(allText)) {
    motivos.push(`Texto contém sensacionalismo: ${p.source}`);
  }
}

// 4. Termos proibidos
const proibidos = [
  /\bb2b\b/i,
  /visita\s+t[eé]cnica/i,
  /parceiro?\s+(da\s+)?meta/i,
  /parceiro?\s+(do\s+)?facebook/i,
  /parceiro?\s+(do\s+)?instagram/i,
  /conv[eê]nio\s+.{0,15}(guarda|pol[ií]cia|municipal|prefeitura)/i,
  /integra[cç][aã]o\s+oficial\s+com\s+[oó]rg[aã]o/i
];
for (const p of proibidos) {
  if (p.test(allText)) {
    motivos.push(`Texto contém termo proibido: ${p.source}`);
  }
}

// 5. CTA seguro
const ctasPermitidos = [
  /avalia[cç][aã]o\s+t[eé]cnica/i,
  /chame?\s+(no\s+)?direct/i,
  /envie?\s+(uma\s+)?mensagem/i,
  /fale?\s+com\s+a\s+dl/i,
  /entre\s+em\s+contato/i,
  /agende/i,
  /solicite/i
];
const ctaSeguro = ctasPermitidos.some(p => p.test(cta));
if (!ctaSeguro && cta.length > 5) {
  ajustes.push('CTA pode não estar alinhado com os padrões permitidos. Revisar.');
}

// 6. Image prompt check
const imgPrompt = (post.image_prompt_en || '').toLowerCase();
const imgProibido = [
  /face\b/i, /portrait/i, /panic/i, /fire.*real/i, /accident/i,
  /victim/i, /tragedy/i, /blood/i, /weapon/i, /gun/i,
  /license\s*plate/i, /car\s*plate/i, /apartment\s*number/i,
  /facebook\s*logo/i, /instagram\s*logo/i, /meta\s*logo/i,
  /whatsapp\s*logo/i, /videogame/i, /3d\s*render/i
];
for (const p of imgProibido) {
  if (p.test(imgPrompt)) {
    motivos.push(`Image prompt contém elemento proibido: ${p.source}`);
  }
}

// 7. Gramática básica (check para legenda vazia)
if (legendaFB.length < 50) {
  motivos.push('Legenda Facebook muito curta (< 50 caracteres)');
}
if (legendaIG.length < 50) {
  motivos.push('Legenda Instagram muito curta (< 50 caracteres)');
}

// --- RESULTADO ---
let status_killcritic = 'APROVADO';
let aprovado = true;
let precisa_humano = false;

if (motivos.length > 0) {
  status_killcritic = 'BLOQUEADO';
  aprovado = false;
} else if (ajustes.length > 0) {
  status_killcritic = 'APROVADO_COM_RESSALVAS';
  aprovado = true;
}

const resultado = {
  ...post,
  aprovado_killcritic: aprovado,
  status_killcritic: status_killcritic,
  motivos_bloqueio: motivos,
  ajustes_recomendados: ajustes,
  precisa_aprovacao_humana: precisa_humano
};

return [{ json: resultado }];

